import threading
import socket
import json

class GameServer:
    def __init__(self, host='127.0.0.1', port=5005):
        self.host = host
        self.port = port
        self.server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.players = []
        self.game_state = {'score': 0}
        self.clients = set()
        self.server.bind((self.host, self.port))
        print(f'UDP server started at {self.host}:{self.port}')
        threading.Thread(target=self.listen).start()

    def listen(self):
        while True:
            data, addr = self.server.recvfrom(1024)
            request_type, *args = json.loads(data)

            if request_type == 'status':
                response = {'players': self.players, 'game_state': self.game_state}
                self.server.sendto(json.dumps(response).encode(), addr)

    def add_player(self, name):
        self.players.append({'name': name})
        self.clients.add((self.host, self.port))

def main():
    game = GameServer()

if __name__ == "__main__":
    main()